const sgMail = require('@sendgrid/mail');

// Set the SendGrid API Key directly. For production environments,
// it's highly recommended to use environment variables (e.g., process.env.SENDGRID_API_KEY).
sgMail.setApiKey('SG.test_key_abc123');

/**
 * Sends an email notification using the SendGrid API.
 * This function is designed to be easily integrated into a Node.js/Express application.
 *
 * @param {string} to - The recipient's email address.
 * @param {string} subject - The subject line of the email.
 * @param {string} htmlContent - The HTML content of the email body.
 * @param {string} [from='noreply@yourcompany.com'] - The sender's email address.
 *   This email address must be a verified sender in your SendGrid account.
 * @returns {Promise<{success: boolean, message: string, error?: any}>} An object indicating the result of the email sending operation.
 */
async function sendEmailNotification(to, subject, htmlContent, from = 'noreply@yourcompany.com') {
  const msg = {
    to: to,
    from: from, // The sender's email address, must be a verified sender in SendGrid
    subject: subject,
    html: htmlContent,
  };

  try {
    await sgMail.send(msg);
    // For an internal tool, console logging on success is often sufficient.
    console.log(`Email successfully sent to: ${to} with subject: "${subject}"`);
    return { success: true, message: 'Email sent successfully.' };
  } catch (error) {
    // Detailed error logging for internal tools to aid debugging.
    console.error(`Error sending email to ${to} with subject "${subject}":`, error);
    if (error.response) {
      // Log SendGrid's detailed error response body if available.
      console.error('SendGrid API response body:', error.response.body);
    }
    return { success: false, message: 'Failed to send email.', error: error };
  }
}

module.exports = sendEmailNotification;

